    // 6. Attempt transactional update that would create cycle (C -> A)
    try {
        // Start transactional update
        graph.beginTransaction();

        // This should create a cycle: A->B->C->A
        graph.addDependency(nodeC, nodeA);

        // If we reach here, commit should throw due to cycle detection
        graph.commitTransaction();
    }
    catch (const std::exception& e) {
