Here's the complete implementation of the header file:

```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

struct AlwaysTriggerResult {
    int recomputeCountAfterInit;
    int recomputeCountAfterDuplicateWrite;
};

AlwaysTriggerResult test_always_trigger(int initialValue) {
    // 1. Create a reactive variable
    reaction::Var<int> valueVar(initialValue);

    // 2. Create a counter to track recomputation count
    int recomputeCount = 0;

    // 3. Create an AlwaysTrig calculation that doubles the value and increments counter
    auto doubleCalc = reaction::Calc<int, reaction::AlwaysTrig>(
        [&recomputeCount, &valueVar]() {
            recomputeCount++;
            return valueVar.Get() * 2;
        }
    );

    // 4. Store recompute count after initialization
    int afterInit = recomputeCount;

    // 5. Write the same value again
    valueVar.Set(initialValue);

    // 6. Store recompute count after duplicate write
    int afterDuplicateWrite = recomputeCount;

    // 7. Force evaluation to avoid unused variable warnings
    reaction::Observe([&doubleCalc]() {
        return doubleCalc.Get();
    });

    // 8. Return result with recompute counts
    return AlwaysTriggerResult{afterInit, afterDuplicateWrite};
}

}  // namespace test_reaction
```

This implementation:

1. Creates a reactive variable using `reaction::Var<int>`
2. Tracks recomputation count with a simple integer counter
3. Uses `reaction::Calc<int, reaction::AlwaysTrig>` to create a calculation that always triggers on dependency changes
4. Stores the initial recompute count after the calculation is created
5. Writes the same value again to test the AlwaysTrig behavior
6. Stores the recompute count after the duplicate write
7. Forces evaluation using `reaction::Observe` to ensure the calculation is actually computed
8. Returns the result structure with both recompute counts

The key aspect is using `reaction::AlwaysTrig` as the trigger policy, which ensures the calculation recomputes even when the same value is written to the reactive variable.

