    bool m_lastReportedChange;
};

/**
 * Function: test_atomic_compound_helpers
 *
 * Demonstrates the low-level atomic compound helper APIs:
 * - atomicCompoundAssign
 * - atomicAddAssign
 * - atomicMultiplyAssign
 * - atomicBitwiseAndAssign
 * - atomicLeftShiftAssign
 * - atomicIncrement
 *
 * These helpers operate on a simple IntAtomicImpl type instead of a full
 * React wrapper, making it easy to observe value and change reporting.
 *
 * @param initial Initial integer value
 * @return AtomicHelperSnapshot
 *         Snapshot containing the final value and which operations reported
 *         that a change occurred.
 */
inline AtomicHelperSnapshot test_atomic_compound_helpers(int32_t initial) {
    IntAtomicImpl atomicImpl(initial);

    // Apply atomic compound assignment (add)
    bool addReportedChange = reaction::atomicCompoundAssign(atomicImpl, 5, 
        [](int32_t& value, int32_t operand) {
            int32_t old = value;
            value += operand;
            return old != value;
        });

    // Check if add operation reported change
    bool addChange = atomicImpl.lastReportedChange();

    // Apply atomic multiply assignment
    bool multiplyReportedChange = reaction::atomicMultiplyAssign(atomicImpl, 3);

    // Check if multiply operation reported change
    bool multiplyChange = atomicImpl.lastReportedChange();

    // Apply atomic bitwise AND assignment
    bool andReportedChange = reaction::atomicBitwiseAndAssign(atomicImpl, 0x0F);

    // Check if bitwise AND operation reported change
    bool andChange = atomicImpl.lastReportedChange();

    // Apply atomic left shift assignment
    bool leftShiftReportedChange = reaction::atomicLeftShiftAssign(atomicImpl, 2);

    // Check if left shift operation reported change
    bool leftShiftChange = atomicImpl.lastReportedChange();

    // Apply atomic increment
    bool incrementReportedChange = reaction::atomicIncrement(atomicImpl);

    // Check if increment operation reported change
    bool incrementChange = atomicImpl.lastReportedChange();

    // Get final value
    int32_t finalValue = atomicImpl.value();

    // Return atomic helper snapshot
    return AtomicHelperSnapshot{
        finalValue,
        addChange,
        multiplyChange,
        andChange,
        leftShiftChange,
        incrementChange
    };
}

